function displayComments(comments) {
    const commentsDiv = document.getElementById('comments');
    commentsDiv.innerHTML = ''; // Clear existing comments

    comments.forEach(comment => {
        const sanitizedComment = document.createElement('div');
        sanitizedComment.textContent = comment; // Automatically escapes HTML
        commentsDiv.appendChild(sanitizedComment);
    });
}

// Example usage
